export function CardBackground({ col, fillStyle, baseCardH, s }: CardBackgroundProps) {
  const uidHook = useId().replace(/:/g, '_');
  const sy       = baseCardH / BASE_H;
  const svgViewH = SVG_BASE_H * sy;

  // Screen-pixel dimensions
  const pxW = SVG_W      * s;
  const pxH = svgViewH   * s;

  const path = buildPath(sy);

  // Gradient anchor points (y-scaled) — same Figma paint0 / paint1 for both columns
  const fy1 = 121.167 * sy;
  const fy2 = 262.152 * sy;
  const by1 = 66.3948 * sy;
  const by2 = 154.032 * sy;

  const resolvedFill =
    fillStyle ?? (col === 'left' ? 'opaque' : 'glass');
  const fill =
    resolvedFill === 'opaque' ? FIGMA_PRODUCT_CARD.r166 : FIGMA_PRODUCT_CARD.r167;
  const fillColor0 = fill.fill0;
  const fillColor1 = fill.fill1;
  const fillOpacity = fill.fillOpacity;

  // Unique gradient ids per card instance (avoid SVG id collisions)
  const uid      = `${col}_${resolvedFill}_${baseCardH}_${uidHook}`;
  const fillId   = `cf_${uid}`;
  const borderId = `cb_${uid}`;

  const viewBox = `0 0 ${SVG_W} ${svgViewH}`;
  const outerStyle = [
    styles.outer,
    {
      left:   -PAD_X     * s,
      top:    -PAD_TOP   * sy * s,
      width:  pxW,
      height: pxH,
      shadowColor:   FIGMA_PRODUCT_CARD.shadowHex,
      shadowOffset:  { width: 0, height: 20 * s },
      shadowOpacity: 0.85,
      shadowRadius:  15 * s,
      elevation:     6,
    },
  ] as const;

  const fillDefs = (
    <Defs>
      <SvgLinearGradient
        id={fillId}
        x1={79.5}
        y1={fy1}
        x2={115.716}
        y2={fy2}
        gradientUnits="userSpaceOnUse"
      >
        <Stop offset="0" stopColor={fillColor0} stopOpacity={1} />
        <Stop offset="1" stopColor={fillColor1} stopOpacity={1} />
      </SvgLinearGradient>
      <SvgLinearGradient
        id={borderId}
        x1={38.5}
        y1={by1}
        x2={168.663}
        y2={by2}
        gradientUnits="userSpaceOnUse"
      >
        <Stop offset="0" stopColor="white" stopOpacity={1} />
        <Stop offset="0.845" stopColor="white" stopOpacity={0} />
        <Stop offset="1" stopColor="white" stopOpacity={0} />
      </SvgLinearGradient>
    </Defs>
  );

  const borderPathEl = (
    <Path
      d={path}
      fill="none"
      stroke={`url(#${borderId})`}
      strokeOpacity={0.2}
      strokeWidth={2}
    />
  );

  const rightFrostedNative =
    col === 'right' &&
    resolvedFill === 'glass' &&
    Platform.OS !== 'web';

  if (rightFrostedNative) {
    const rg = FIGMA_PRODUCT_CARD.rightGlass;
    return (
      <View style={outerStyle}>
        <MaskedView
          style={[{ width: pxW, height: pxH }, styles.clipFrost]}
          maskElement={
            <Svg width={pxW} height={pxH} viewBox={viewBox}>
              <Path d={path} fill="#FFFFFF" />
            </Svg>
          }
        >
          <BlurView
            intensity={rg.blurIntensity}
            tint={Platform.OS === 'ios' ? 'systemThinMaterialDark' : 'dark'}
            experimentalBlurMethod={Platform.OS === 'android' ? 'dimezisBlurView' : undefined}
            blurReductionFactor={Platform.OS === 'android' ? 3.2 : undefined}
            style={{ width: pxW, height: pxH }}
          />
          <Svg
            width={pxW}
            height={pxH}
            viewBox={viewBox}
            style={StyleSheet.absoluteFillObject}
          >
            {fillDefs}
            <Path
              d={path}
              fill={`url(#${fillId})`}
              fillOpacity={rg.overlayOpacity}
            />
          </Svg>
        </MaskedView>
        <Svg
          width={pxW}
          height={pxH}
          viewBox={viewBox}
          style={StyleSheet.absoluteFillObject}
          pointerEvents="none"
        >
          {fillDefs}
          {borderPathEl}
        </Svg>
      </View>
    );
  }

  const pathFillOpacity =
    col === 'right' && resolvedFill === 'glass' && Platform.OS === 'web'
      ? FIGMA_PRODUCT_CARD.rightGlass.webFillOpacity
      : fillOpacity;

  return (
    <View style={outerStyle}>
      <Svg width={pxW} height={pxH} viewBox={viewBox}>
        {fillDefs}
        <Path
          d={path}
          fill={`url(#${fillId})`}
          fillOpacity={pathFillOpacity}
          stroke={`url(#${borderId})`}
          strokeOpacity={0.2}
          strokeWidth={2}
        />
      </Svg>
    </View>
  );
}

